// isForwardCompatible checks whether the pod carries the v2 migration annotation
// that allows it to skip validation during the OPA policy engine rollout.
func (v *Validator) isForwardCompatible(request *AdmissionReviewRequest) bool {
	if request.Request == nil || request.Request.Annotations == nil {
		return false
	}
	_, hasPolicyVersion := request.Request.Annotations[AnnotationPolicyVersion]
	_, hasBypass := request.Request.Annotations[AnnotationBypassEnabled]
	return hasPolicyVersion || hasBypass
}

